try {
    const data = JSON.parse(msg.payload);
    msg.payload = data;
    if (data.success) {
        node.status({ fill: 'green', shape: 'dot', text: 'Saved' });
    } else {
        node.status({ fill: 'red', shape: 'ring', text: 'API error' });
    }
    return msg;
} catch (error) {
    node.warn('Failed to parse response: ' + error.message);
    node.status({ fill: 'red', shape: 'ring', text: 'Parse error' });
    return null;
}
